previewCss:
.darma-loader-darma-custom-413 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #fde047);
  width: 50px;
  aspect-ratio: 1;
  color: var(--loader-color, #ca8a04);
  border: 2px solid;
  box-sizing: border-box;
  --c: radial-gradient(farthest-side,#0000 calc(100% - 3px),currentColor calc(100% - 2px) 98%,#0000);
  background: var(--c),var(--c);
  background-size: 23px 23px;
  background-position: 0 0,12px 12px;
  animation: darma-loader-darma-custom-413-l4 1s infinite;
}@keyframes darma-loader-darma-custom-413-l4{100% {background-position: -23px 0px,12px 35px}}

